if (! function_exists('network_dns_lookup')) {
    function network_dns_lookup($hostname, $record_type = null, $timeout = null, $resolve_only = null)
    {
            $hostname = $hostname ?? '';
            $record_type = $record_type ?? 'A';
            $timeout = $timeout ?? 5;
            $resolve_only = $resolve_only ?? false;

            $timeout = max(1, min(15, (int)$timeout));
            $hostname = trim($hostname);

            if (empty($hostname)) {
                return ['success' => false, 'error' => 'Hostname is required.'];
            }

            // Map record type string to PHP DNS_* constants
            $type_map = [
                'A' => DNS_A,
                'AAAA' => DNS_AAAA,
                'MX' => DNS_MX,
                'NS' => DNS_NS,
                'TXT' => DNS_TXT,
                'SOA' => DNS_SOA,
                'CNAME' => DNS_CNAME,
                'PTR' => DNS_PTR,
                'ANY' => DNS_ANY,
            ];

            $type_upper = strtoupper($record_type);
            $dns_type = $type_map[$type_upper] ?? DNS_A;

            // Determine if this looks like an IP address
            $is_ip = preg_match('/^\d+\.\d+\.\d+\.\d+$/', $hostname);
            $is_ipv6 = (substr_count($hostname, ':') >= 2);

            // Simple resolve mode (just IPs)
            if ($resolve_only) {
                $ip = @gethostbyname($hostname);
                if ($ip === $hostname) {
                    return ['success' => false, 'error' => 'Hostname resolution failed.', 'hostname' => $hostname];
                }
                // Get additional IPs by doing a full DNS query
                $all_records = @dns_get_record($hostname, DNS_A);
                $ips = [];
                if (is_array($all_records)) {
                    foreach ($all_records as $r) {
                        if (($r['type'] ?? '') === 'A' && !empty($r['ip'])) {
                            $ips[] = $r['ip'];
                        }
                    }
                }
                $ips = array_unique($ips);
                if (empty($ips)) $ips = [$ip];

                return [
                    'success' => true,
                    'hostname' => $hostname,
                    'resolved_ips' => $ips,
                    'record_count' => count($ips),
                    'method' => 'gethostbyname + dns_get_record',
                ];
            }

            // Full DNS record lookup
            $records = @dns_get_record($hostname, $dns_type);
            if ($records === false || !is_array($records)) {
                // Try gethostbyname as fallback for basic A lookup
                $ip = @gethostbyname($hostname);
                if ($ip === $hostname) {
                    return [
                        'success' => false,
                        'error' => 'DNS query failed. Hostname may not exist or DNS server unreachable.',
                        'hostname' => $hostname,
                        'record_type' => $type_upper,
                    ];
                }
                // Fallback: we got an IP from gethostbyname
                return [
                    'success' => true,
                    'hostname' => $hostname,
                    'record_type' => 'A (fallback)',
                    'records' => [
                        ['host' => $hostname, 'type' => 'A', 'ip' => $ip, 'ttl' => 0, 'class' => 'IN'],
                    ],
                    'record_count' => 1,
                    'fallback' => true,
                ];
            }

            // If we requested PTR but the hostname is an IP, try the reverse
            if ($type_upper === 'PTR' && ($is_ip || $is_ipv6)) {
                $rev_host = $is_ip 
                    ? implode('.', array_reverse(explode('.', $hostname))) . '.in-addr.arpa'
                    : '';
                if (!empty($rev_host)) {
                    $ptr_records = @dns_get_record($rev_host, DNS_PTR);
                    if ($ptr_records !== false && is_array($ptr_records)) {
                        $records = $ptr_records;
                    }
                }
            }

            // Process and clean up records
            $clean = [];
            $seen = [];
            foreach ($records as $r) {
                if (!is_array($r) && !is_object($r)) continue;
                $r = (array)$r;
                $key = ($r['host'] ?? '') . '|' . ($r['type'] ?? '') . '|' . ($r['target'] ?? $r['ip'] ?? $r['txt'] ?? '');
                if (isset($seen[$key])) continue;
                $seen[$key] = true;

                $entry = [
                    'host' => $r['host'] ?? '',
                    'type' => $r['type'] ?? '',
                    'ttl' => $r['ttl'] ?? 0,
                    'class' => $r['class'] ?? 'IN',
                ];

                switch ($r['type'] ?? '') {
                    case 'A':
                        $entry['ip'] = $r['ip'] ?? '';
                        break;
                    case 'AAAA':
                        $entry['ipv6'] = $r['ipv6'] ?? '';
                        break;
                    case 'MX':
                        $entry['target'] = $r['target'] ?? '';
                        $entry['priority'] = $r['pri'] ?? 0;
                        break;
                    case 'NS':
                        $entry['target'] = $r['target'] ?? '';
                        break;
                    case 'TXT':
                        $entry['txt'] = $r['txt'] ?? '';
                        break;
                    case 'SOA':
                        $entry['mname'] = $r['mname'] ?? '';
                        $entry['rname'] = $r['rname'] ?? '';
                        $entry['serial'] = (int)($r['serial'] ?? 0);
                        $entry['refresh'] = (int)($r['refresh'] ?? 0);
                        $entry['retry'] = (int)($r['retry'] ?? 0);
                        $entry['expire'] = (int)($r['expire'] ?? 0);
                        $entry['minimum_ttl'] = (int)($r['minimum-ttl'] ?? 0);
                        break;
                    case 'CNAME':
                        $entry['target'] = $r['target'] ?? '';
                        break;
                    case 'PTR':
                        $entry['target'] = $r['target'] ?? '';
                        break;
                }
                $clean[] = $entry;
            }

            // Also do a simple reverse PTR lookup using gethostbyaddr if this was a PTR query on an IP
            $reverse_name = null;
            if ($type_upper === 'PTR' && ($is_ip || $is_ipv6) && empty($clean)) {
                $reverse_name = @gethostbyaddr($hostname);
                if ($reverse_name !== false && $reverse_name !== $hostname) {
                    $clean[] = [
                        'host' => $hostname,
                        'type' => 'PTR',
                        'ttl' => 0,
                        'class' => 'IN',
                        'target' => $reverse_name,
                        'method' => 'gethostbyaddr',
                    ];
                }
            }

            // Summary
            $type_counts = [];
            foreach ($clean as $r) {
                $t = $r['type'] ?? 'UNKNOWN';
                $type_counts[$t] = ($type_counts[$t] ?? 0) + 1;
            }

            return [
                'success' => true,
                'hostname' => $hostname,
                'record_type' => $type_upper,
                'record_count' => count($clean),
                'type_breakdown' => $type_counts,
                'records' => $clean,
                'reverse_name' => $reverse_name,
                'auth' => isset($records['auth']) ? $records['auth'] : [],
                'addtl' => isset($records['addtl']) ? $records['addtl'] : [],
            ];
